code = """import json

# Load data
civic_docs_data = json.load(open(var_functions.query_db:26, 'r'))
funding_records = var_functions.query_db:48

# Build project status map
status_map = {}
for doc in civic_docs_data:
    text = doc.get('text', '')
    lines = text.split('\n')
    current_section = None
    
    for line in lines:
        line = line.strip()
        if not line:
            continue
            
        # Detect sections
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            current_section = 'not_started'
        
        # Map project to status
        if current_section and line and len(line) > 10 and not line.startswith('('):
            if 'Updates' not in line and 'Schedule' not in line and 'Project Description' not in line and 'Page' not in line:
                base = line.split('(')[0].strip()
                if base:
                    status_map[base] = 'completed' if current_section == 'construction' else current_section

# Get final results
output_list = []
for rec in funding_records:
    pname = rec['Project_Name']
    base = pname.split('(')[0].strip()
    status_val = 'unknown'
    
    if base in status_map:
        status_val = status_map[base]
    
    output_list.append([
        pname,
        rec['Funding_Source'],
        int(rec['Amount']),
        status_val
    ])

# Format the output
formatted_lines = []
for item in sorted(output_list, key=lambda x: x[0]):
    formatted_lines.append(f'Project: {item[0]}')
    formatted_lines.append(f'Funding Source: {item[1]}')
    formatted_lines.append(f'Amount: ${item[2]:,}')
    formatted_lines.append(f'Status: {item[3]}')
    formatted_lines.append('-' * 70)

final_output = '\n'.join(formatted_lines)
total_count = len(output_list)
total_funding_sum = sum(item[2] for item in output_list)

result = {
    'total_projects': total_count,
    'total_funding': total_funding_sum,
    'data': final_output
}

print('__RESULT__:')
print(json.dumps(result))"""

